import { MapContainer, TileLayer } from "react-leaflet";
import { useEffect, useState } from "react";
import PlaneMarker from "../components/PlaneMarker";
import "leaflet/dist/leaflet.css";
import "./Dashboard.css";

export default function Dashboard() {
  const [flightNo, setFlightNo] = useState("");
  const [position, setPosition] = useState([20, 77]); // India center
  const [flightData, setFlightData] = useState(null);

  const fetchFlight = async () => {
    try {
      const res = await fetch(
        "https://opensky-network.org/api/states/all"
      );
      const data = await res.json();

      const flights = data.states;

      // Match callsign (trim spaces)
      const match = flights.find(
        (f) =>
          f[1] &&
          f[1].trim().toUpperCase() === flightNo.toUpperCase()
      );

      if (match) {
        const lat = match[6];
        const lng = match[5];

        setPosition([lat, lng]);

        setFlightData({
          callsign: match[1].trim(),
          velocity: match[9],
          altitude: match[7],
        });
      } else {
        alert("Flight not found (try ICAO callsign like AIC202)");
      }
    } catch (err) {
      console.error(err);
    }
  };

  // Live updates every 5 sec
  useEffect(() => {
    const interval = setInterval(() => {
      if (flightNo) fetchFlight();
    }, 5000);

    return () => clearInterval(interval);
  }, [flightNo]);

  return (
    <div className="dashboard">
      {/* PANEL */}
      <div className="panel">
        ✈️ Real Flight Tracker

        <input
          type="text"
          value={flightNo}
          onChange={(e) => setFlightNo(e.target.value)}
          placeholder="Enter Callsign (AIC202)"
        />

        <button onClick={fetchFlight}>Track</button>

        <p>
          {flightData
            ? `Tracking: ${flightData.callsign}`
            : "Enter flight callsign"}
        </p>
      </div>

      {/* MAP */}
      <MapContainer center={position} zoom={5} className="map">
        <TileLayer url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png" />

        <PlaneMarker position={position} flightData={flightData} />
      </MapContainer>
    </div>
  );
}
